head.b:skin:
/* ============================================
   Mi Biblia 365 - Sistema de Diseño | Z.IA
   ============================================ */

:root {
  /* Colores modo claro */
  --bg-primary: #faf9f7;
  --bg-secondary: #ffffff;
  --bg-tertiary: #f5f3ef;
  --bg-card: #ffffff;
  --bg-elevated: #ffffff;

  --text-primary: #1a1a1a;
  --text-secondary: #4a4a4a;
  --text-tertiary: #6b6b6b;
  --text-muted: #8b8b8b;

  --accent-primary: #1a365d;
  --accent-secondary: #2c5282;
  --accent-tertiary: #3182ce;
  --accent-gold: #b7791f;
  --accent-gold-light: #d69e2e;

  --border-light: #e8e6e3;
  --border-medium: #d4d2cf;

  --shadow-sm: 0 1px 2px rgba(26, 54, 93, 0.04);
  --shadow-md: 0 4px 12px rgba(26, 54, 93, 0.08);
  --shadow-lg: 0 8px 24px rgba(26, 54, 93, 0.12);

  --radius-sm: 6px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 24px;

  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  --font-serif: 'Playfair Display', Georgia, serif;

  --transition-fast: 150ms ease;
  --transition-base: 250ms ease;
  --transition-slow: 400ms ease;

  --spacing-xs: 4px;
  --spacing-sm: 8px;
  --spacing-md: 16px;
  --spacing-lg: 24px;
  --spacing-xl: 32px;
  --spacing-2xl: 48px;
  --spacing-3xl: 64px;

  --nav-height: 64px;
  --nav-mobile-height: 56px;
  --bottom-nav-height: 72px;

  --safe-area-inset-bottom: env(safe-area-inset-bottom, 0px);
}

/* Modo oscuro */
[data-theme="dark"] {
  --bg-primary: #0d1117;
  --bg-secondary: #161b22;
  --bg-tertiary: #1c2128;
  --bg-card: #161b22;
  --bg-elevated: #21262d;

  --text-primary: #f0f6fc;
  --text-secondary: #c9d1d9;
  --text-tertiary: #8b949e;
  --text-muted: #6e7681;

  --accent-primary: #58a6ff;
  --accent-secondary: #79c0ff;
  --accent-tertiary: #a5d6ff;
  --accent-gold: #d29922;
  --accent-gold-light: #e3b341;

  --border-light: #30363d;
  --border-medium: #484f58;

  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.2);
  --shadow-md: 0 4px 12px rgba(0, 0, 0, 0.3);
  --shadow-lg: 0 8px 24px rgba(0, 0, 0, 0.4);
}

/* Reset y base */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
  scroll-behavior: smooth;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: var(--font-sans);
  background-color: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.6;
  min-height: 100vh;
  overflow-x: hidden;
  transition: background-color var(--transition-base), color var(--transition-base);
}

/* Ocultar elementos de Blogger */
.widget { display: none !important; }
#blog1 { display: none !important; }
.blog-feeds { display: none !important; }
.post-feeds { display: none !important; }
.feed-links { display: none !important; }
.blog-pager { display: none !important; }

/* ============================================
   Layout Principal
   ============================================ */

.app-container {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

/* Header */
.app-header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  height: var(--nav-height);
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border-light);
  z-index: 100;
  display: flex;
  align-items: center;
  padding: 0 var(--spacing-lg);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

.header-content {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
}

.logo {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  text-decoration: none;
  color: var(--text-primary);
}

.logo-icon {
  width: 36px;
  height: 36px;
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
}

.logo-icon svg {
  width: 20px;
  height: 20px;
  color: white;
}

.logo-text {
  font-family: var(--font-serif);
  font-size: 1.25rem;
  font-weight: 600;
  letter-spacing: -0.02em;
}

.logo-text span {
  color: var(--accent-gold);
}

/* Navegación desktop */
.nav-desktop {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
}

.nav-link {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm) var(--spacing-md);
  color: var(--text-secondary);
  text-decoration: none;
  font-size: 0.9rem;
  font-weight: 500;
  border-radius: var(--radius-md);
  transition: all var(--transition-fast);
}

.nav-link:hover {
  background: var(--bg-tertiary);
  color: var(--text-primary);
}

.nav-link.active {
  background: var(--bg-tertiary);
  color: var(--accent-primary);
}

.nav-link svg {
  width: 18px;
  height: 18px;
}

/* Acciones del header */
.header-actions {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
}

.btn-icon {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-md);
  border: none;
  background: transparent;
  color: var(--text-secondary);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all var(--transition-fast);
}

.btn-icon:hover {
  background: var(--bg-tertiary);
  color: var(--text-primary);
}

.btn-icon svg {
  width: 20px;
  height: 20px;
}

/* Contenido principal */
.main-content {
  flex: 1;
  padding-top: var(--nav-height);
  padding-bottom: calc(var(--bottom-nav-height) + var(--safe-area-inset-bottom));
}

/* Navegación móvil inferior */
.nav-mobile {
  display: none;
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  height: calc(var(--bottom-nav-height) + var(--safe-area-inset-bottom));
  padding-bottom: var(--safe-area-inset-bottom);
  background: var(--bg-secondary);
  border-top: 1px solid var(--border-light);
  z-index: 100;
}

.nav-mobile-inner {
  display: flex;
  align-items: center;
  justify-content: space-around;
  height: var(--bottom-nav-height);
  padding: 0 var(--spacing-sm);
}

.nav-mobile-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 2px;
  padding: var(--spacing-sm) var(--spacing-md);
  color: var(--text-tertiary);
  text-decoration: none;
  font-size: 0.7rem;
  font-weight: 500;
  border-radius: var(--radius-md);
  transition: all var(--transition-fast);
  min-width: 64px;
}

.nav-mobile-item svg {
  width: 24px;
  height: 24px;
}

.nav-mobile-item.active {
  color: var(--accent-primary);
}

.nav-mobile-item.leer-hoy {
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
  color: white;
  padding: var(--spacing-md);
  border-radius: 50%;
  min-width: 56px;
  height: 56px;
  margin-top: -20px;
  box-shadow: var(--shadow-lg);
}

.nav-mobile-item.leer-hoy svg {
  width: 26px;
  height: 26px;
}

/* ============================================
   Contenedores de páginas
   ============================================ */

.page-container {
  max-width: 800px;
  margin: 0 auto;
  padding: var(--spacing-lg);
}

.page-container.wide {
  max-width: 1200px;
}

/* Página de inicio */
.home-hero {
  text-align: center;
  padding: var(--spacing-2xl) var(--spacing-lg);
}

.home-greeting {
  font-size: 0.95rem;
  color: var(--text-tertiary);
  margin-bottom: var(--spacing-sm);
}

.home-title {
  font-family: var(--font-serif);
  font-size: 2rem;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: var(--spacing-md);
  line-height: 1.2;
}

.home-subtitle {
  font-size: 1rem;
  color: var(--text-secondary);
  max-width: 400px;
  margin: 0 auto var(--spacing-xl);
}

/* Botones */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-md) var(--spacing-xl);
  font-family: var(--font-sans);
  font-size: 0.95rem;
  font-weight: 600;
  border-radius: var(--radius-md);
  border: none;
  cursor: pointer;
  text-decoration: none;
  transition: all var(--transition-fast);
}

.btn-primary {
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
  color: white;
  box-shadow: var(--shadow-md);
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-lg);
}

.btn-secondary {
  background: var(--bg-tertiary);
  color: var(--text-primary);
  border: 1px solid var(--border-light);
}

.btn-secondary:hover {
  background: var(--bg-elevated);
  border-color: var(--border-medium);
}

.btn-lg {
  padding: var(--spacing-lg) var(--spacing-2xl);
  font-size: 1.05rem;
  border-radius: var(--radius-lg);
}

.btn svg {
  width: 18px;
  height: 18px;
}

/* Cards */
.card {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: var(--radius-lg);
  padding: var(--spacing-lg);
  box-shadow: var(--shadow-sm);
  transition: all var(--transition-base);
}

.card:hover {
  box-shadow: var(--shadow-md);
}

/* Versículo del día */
.verse-card {
  background: linear-gradient(135deg, var(--bg-card), var(--bg-tertiary));
  border: 1px solid var(--border-light);
  border-radius: var(--radius-xl);
  padding: var(--spacing-xl);
  margin: var(--spacing-xl) 0;
  position: relative;
  overflow: hidden;
}

.verse-card::before {
  content: '"';
  position: absolute;
  top: -20px;
  left: 20px;
  font-family: var(--font-serif);
  font-size: 120px;
  color: var(--accent-primary);
  opacity: 0.08;
  line-height: 1;
}

.verse-label {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-xs);
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--accent-gold);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: var(--spacing-md);
}

.verse-text {
  font-family: var(--font-serif);
  font-size: 1.25rem;
  line-height: 1.7;
  color: var(--text-primary);
  margin-bottom: var(--spacing-md);
  font-style: italic;
}

.verse-reference {
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--accent-primary);
}

/* Progreso */
.progress-section {
  margin: var(--spacing-xl) 0;
}

.progress-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: var(--spacing-md);
}

.progress-title {
  font-weight: 600;
  color: var(--text-primary);
}

.progress-percent {
  font-size: 0.85rem;
  color: var(--accent-primary);
  font-weight: 600;
}

.progress-bar {
  height: 8px;
  background: var(--bg-tertiary);
  border-radius: 100px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--accent-primary), var(--accent-gold));
  border-radius: 100px;
  transition: width var(--transition-slow);
}

/* Quick actions */
.quick-actions {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--spacing-md);
  margin: var(--spacing-xl) 0;
}

.quick-action {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-lg);
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: var(--radius-lg);
  text-decoration: none;
  color: var(--text-primary);
  transition: all var(--transition-fast);
}

.quick-action:hover {
  border-color: var(--accent-primary);
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}

.quick-action-icon {
  width: 48px;
  height: 48px;
  background: var(--bg-tertiary);
  border-radius: var(--radius-md);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--accent-primary);
}

.quick-action-icon svg {
  width: 24px;
  height: 24px;
}

.quick-action-label {
  font-size: 0.9rem;
  font-weight: 500;
}

/* Planes grid */
.plans-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: var(--spacing-lg);
  margin: var(--spacing-xl) 0;
}

.plan-card {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: var(--radius-lg);
  padding: var(--spacing-lg);
  transition: all var(--transition-base);
}

.plan-card:hover {
  border-color: var(--accent-primary);
  box-shadow: var(--shadow-md);
}

.plan-card-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  margin-bottom: var(--spacing-md);
}

.plan-icon {
  width: 44px;
  height: 44px;
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
  border-radius: var(--radius-md);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
}

.plan-icon svg {
  width: 22px;
  height: 22px;
}

.plan-badge {
  font-size: 0.7rem;
  font-weight: 600;
  padding: 4px 10px;
  background: var(--bg-tertiary);
  color: var(--text-tertiary);
  border-radius: 100px;
}

.plan-name {
  font-size: 1.1rem;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: var(--spacing-xs);
}

.plan-description {
  font-size: 0.85rem;
  color: var(--text-tertiary);
  margin-bottom: var(--spacing-md);
  line-height: 1.5;
}

.plan-meta {
  display: flex;
  gap: var(--spacing-md);
  font-size: 0.8rem;
  color: var(--text-secondary);
}

.plan-meta-item {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
}

.plan-meta-item svg {
  width: 14px;
  height: 14px;
}

/* ============================================
   Loading y estados
   ============================================ */

.skeleton {
  background: linear-gradient(90deg, var(--bg-tertiary) 25%, var(--bg-elevated) 50%, var(--bg-tertiary) 75%);
  background-size: 200% 100%;
  animation: skeleton-loading 1.5s infinite;
  border-radius: var(--radius-sm);
}

@keyframes skeleton-loading {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

.loading-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: var(--spacing-3xl);
  gap: var(--spacing-md);
}

.loading-spinner {
  width: 40px;
  height: 40px;
  border: 3px solid var(--border-light);
  border-top-color: var(--accent-primary);
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ============================================
   Responsive
   ============================================ */

@media (max-width: 768px) {
  :root {
    --nav-height: var(--nav-mobile-height);
  }

  .nav-desktop {
    display: none;
  }

  .nav-mobile {
    display: block;
  }

  .page-container {
    padding: var(--spacing-md);
  }

  .home-hero {
    padding: var(--spacing-lg) var(--spacing-md);
  }

  .home-title {
    font-size: 1.5rem;
  }

  .quick-actions {
    grid-template-columns: 1fr;
  }

  .verse-card {
    padding: var(--spacing-lg);
  }

  .verse-text {
    font-size: 1.1rem;
  }
}

@media (min-width: 769px) {
  .nav-mobile {
    display: none !important;
  }
}

/* ============================================
   Utilidades
   ============================================ */

.hidden { display: none !important; }
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.text-center { text-align: center; }
.text-muted { color: var(--text-tertiary); }

.mt-md { margin-top: var(--spacing-md); }
.mt-lg { margin-top: var(--spacing-lg); }
.mb-md { margin-bottom: var(--spacing-md); }
.mb-lg { margin-bottom: var(--spacing-lg); }

/* Focus states para accesibilidad */
:focus-visible {
  outline: 2px solid var(--accent-primary);
  outline-offset: 2px;
}

/* Reduced motion */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

/* ============================================
   Footer
   ============================================ */

.app-footer {
  padding: var(--spacing-xl) var(--spacing-lg);
  padding-bottom: calc(var(--bottom-nav-height) + var(--safe-area-inset-bottom) + var(--spacing-xl));
  border-top: 1px solid var(--border-light);
  background: var(--bg-secondary);
}

@media (min-width: 769px) {
  .app-footer {
    padding-bottom: var(--spacing-xl);
  }
}

.footer-inner {
  max-width: 1200px;
  margin: 0 auto;
  text-align: center;
}

.footer-text {
  font-size: 0.9rem;
  color: var(--text-secondary);
  font-weight: 600;
  margin-bottom: var(--spacing-sm);
}

.footer-links {
  font-size: 0.85rem;
  color: var(--text-tertiary);
  margin-bottom: var(--spacing-sm);
}

.footer-links a {
  color: var(--accent-primary);
  text-decoration: none;
}

.footer-links a:hover {
  text-decoration: underline;
}

.footer-credit {
  font-size: 0.78rem;
  color: var(--text-muted);
  max-width: 520px;
  margin: var(--spacing-sm) auto;
  line-height: 1.55;
}

.footer-credit a {
  color: var(--accent-primary);
  text-decoration: none;
}

.footer-year {
  font-size: 0.78rem;
  color: var(--text-muted);
  margin-top: var(--spacing-sm);
}

/* ============================================
   Páginas internas (stubs)
   ============================================ */

.static-page {
  max-width: 760px;
  margin: 0 auto;
  padding: var(--spacing-lg);
}

.static-page h1 {
  font-family: var(--font-serif);
  font-size: 1.8rem;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: var(--spacing-sm);
}

.static-page .page-lead {
  font-size: 1rem;
  color: var(--text-secondary);
  margin-bottom: var(--spacing-xl);
}

.static-page section {
  margin-bottom: var(--spacing-xl);
}

.static-page h2 {
  font-size: 1.15rem;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: var(--spacing-sm);
}

.static-page p {
  font-size: 0.95rem;
  color: var(--text-secondary);
  line-height: 1.7;
  margin-bottom: var(--spacing-md);
}

.static-page ul {
  padding-left: var(--spacing-lg);
  color: var(--text-secondary);
  font-size: 0.95rem;
  line-height: 1.7;
}

.static-page ul li {
  margin-bottom: var(--spacing-sm);
}

.faq-item {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: var(--radius-md);
  padding: var(--spacing-lg);
  margin-bottom: var(--spacing-md);
}

.faq-item h3 {
  font-size: 1rem;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: var(--spacing-sm);
}

.faq-item p {
  font-size: 0.9rem;
  color: var(--text-secondary);
  margin: 0;
}

.install-platform {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: var(--radius-md);
  padding: var(--spacing-lg);
  margin-bottom: var(--spacing-md);
}

.install-platform h3 {
  font-size: 1rem;
  font-weight: 600;
  color: var(--accent-primary);
  margin-bottom: var(--spacing-sm);
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
}

.install-platform ol {
  padding-left: var(--spacing-lg);
  color: var(--text-secondary);
  font-size: 0.9rem;
  line-height: 1.7;
}

body.script:
//
(function() {
  'use strict';

  // ==========================================
  // Configuración
  // ==========================================
  const CONFIG = {
    CDN_BASE: 'https://cdn.jsdelivr.net/gh/erzonmr/MiBiblia365-XML@main/',
    API_BASE: 'https://bible-api.deno.dev',
    API_SOURCES: {
      primary: 'https://bible-api.deno.dev',
      secondary: 'https://bible.helloao.org/api'
    },
    DEFAULT_VERSION: 'RV1960',
    SOURCE_PREFERENCE: 'auto',
    STORAGE_KEY: 'mibiblia365_data',
    STORAGE_LEGACY_PREFIX: 'mibiblia365-',
    CHAPTER_CACHE_KEY: 'mibiblia365_chapter_cache_v1',
    REQUEST_TIMEOUT_MS: 12000
  };

  const VERSION_POLICY = {
    netlifyAllowed: {
      rv1960: { id: 'RV1960', name: 'Reina Valera 1960' },
      rv1995: { id: 'RV1995', name: 'Reina Valera 1995' },
      nvi: { id: 'NVI', name: 'Nueva Version Internacional' },
      dhh: { id: 'DHH', name: 'Dios Habla Hoy' },
      pdt: { id: 'PDT', name: 'Palabra de Dios para Todos' }
    }
  };

  const RUNTIME_FLAGS = {
    netlifyCorsBlocked: false
  };

  // ==========================================
  // Estado global
  // ==========================================
  const state = {
    theme: localStorage.getItem('theme') || 'light',
    currentPage: 'home',
    user: null,
    plan: null,
    version: CONFIG.DEFAULT_VERSION
  };

  // ==========================================
  // Utilidades
  // ==========================================
  function $(selector) {
    return document.querySelector(selector);
  }

  function $$(selector) {
    return document.querySelectorAll(selector);
  }

  function show(el) {
    if (el) el.classList.remove('hidden');
  }

  function hide(el) {
    if (el) el.classList.add('hidden');
  }

  function normalizeVersionId(versionId) {
    const raw = String(versionId || '').trim().toUpperCase();
    const map = {
      'RV60': 'RV1960',
      'RVR60': 'RV1960',
      'RVR1960': 'RV1960',
      'RV-1960': 'RV1960',
      'RVR-1960': 'RV1960'
    };
    return map[raw] || raw;
  }

  const BibleService = (function() {
    const memoryCache = new Map();

    function withTimeout(url) {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), CONFIG.REQUEST_TIMEOUT_MS);
      return fetch(url, { signal: controller.signal })
        .finally(() => clearTimeout(timeoutId));
    }

    async function fetchJSON(url) {
      const key = 'json:' + url;
      if (memoryCache.has(key)) return memoryCache.get(key);

      let res;
      try {
        res = await withTimeout(url);
      } catch (e) {
        if (url.indexOf('bible-api.deno.dev') !== -1) {
          RUNTIME_FLAGS.netlifyCorsBlocked = true;
        }
        throw e;
      }
      if (!res.ok) {
        const err = new Error('HTTP ' + res.status + ' at ' + url);
        err.status = res.status;
        if (url.indexOf('bible-api.deno.dev') !== -1 && (res.status === 0 || res.type === 'opaque')) {
          RUNTIME_FLAGS.netlifyCorsBlocked = true;
        }
        throw err;
      }

      const data = await res.json();
      memoryCache.set(key, data);
      return data;
    }

    function readChapterCache() {
      try {
        const raw = localStorage.getItem(CONFIG.CHAPTER_CACHE_KEY);
        return raw ? JSON.parse(raw) : {};
      } catch (_) {
        return {};
      }
    }

    function writeChapterCache(cache) {
      try {
        localStorage.setItem(CONFIG.CHAPTER_CACHE_KEY, JSON.stringify(cache));
      } catch (_) {}
    }

    function setCachedChapter(sourceKey, versionId, bookId, chapter, payload) {
      const key = [sourceKey, normalizeVersionId(versionId), String(bookId).toUpperCase(), Number(chapter)].join('|');
      const cache = readChapterCache();
      cache[key] = { at: Date.now(), data: payload };
      writeChapterCache(cache);
    }

    function getCachedChapter(sourceKey, versionId, bookId, chapter) {
      const key = [sourceKey, normalizeVersionId(versionId), String(bookId).toUpperCase(), Number(chapter)].join('|');
      const cache = readChapterCache();
      return cache[key] ? cache[key].data : null;
    }

    function normalizeSourceKey(sourceKey) {
      return sourceKey === 'netlify' ? 'netlify' : 'helloao';
    }

    function orderSources(versionRecord) {
      const pref = state.user && state.user.config && state.user.config.sourcePreference
        ? state.user.config.sourcePreference
        : CONFIG.SOURCE_PREFERENCE;

      const available = versionRecord && Array.isArray(versionRecord.availableIn)
        ? versionRecord.availableIn.slice()
        : ['netlify', 'helloao'];

      const normalized = available.map(normalizeSourceKey);
      if (pref === 'netlify-first') return ['netlify', 'helloao'].filter(s => normalized.indexOf(s) !== -1);
      if (pref === 'helloao-first') return ['helloao', 'netlify'].filter(s => normalized.indexOf(s) !== -1);
      return ['netlify', 'helloao'].filter(s => normalized.indexOf(s) !== -1);
    }

    function parseHelloChapter(payload, versionId, bookId, chapter) {
      const out = {
        source: 'helloao',
        versionId: normalizeVersionId(versionId),
        bookId: String(bookId).toUpperCase(),
        chapter: Number(chapter),
        verses: []
      };

      if (Array.isArray(payload)) {
        out.verses = payload.map((v, i) => ({
          number: Number(v.verse || v.number || i + 1),
          text: String(v.text || v.content || '').trim()
        }));
        return out;
      }

      const list = payload.verses || payload.data || payload.chapter || [];
      if (Array.isArray(list)) {
        out.verses = list.map((v, i) => ({
          number: Number(v.verse || v.number || i + 1),
          text: String(v.text || v.content || '').trim()
        }));
        return out;
      }

      if (payload && payload.chapter && Array.isArray(payload.chapter.content)) {
        out.verses = payload.chapter.content
          .filter(item => item && item.type === 'verse')
          .map((item, i) => {
            const parts = Array.isArray(item.content) ? item.content : [];
            const text = parts.map(part => {
              if (typeof part === 'string') return part;
              if (part && typeof part.text === 'string') return part.text;
              return '';
            }).join('').trim();
            return {
              number: Number(item.number || i + 1),
              text: text
            };
          })
          .filter(v => v.text);
        return out;
      }

      if (payload && typeof payload.verses === 'object') {
        const keys = Object.keys(payload.verses).sort((a, b) => Number(a) - Number(b));
        out.verses = keys.map((k, i) => ({
          number: Number(k || i + 1),
          text: String(payload.verses[k] || '').trim()
        }));
        return out;
      }

      if (payload && typeof payload.text === 'string') {
        out.verses = [{ number: 1, text: payload.text.trim() }];
      }
      return out;
    }

    function parseNetlifyChapter(payload, versionId, bookId, chapter) {
      const out = {
        source: 'netlify',
        versionId: normalizeVersionId(versionId),
        bookId: String(bookId).toUpperCase(),
        chapter: Number(chapter),
        verses: []
      };

      const list = payload.vers || payload.verses || payload.data || payload.results || [];
      if (Array.isArray(list)) {
        out.verses = list.map((v, i) => ({
          number: Number(v.number || v.verse || i + 1),
          text: String(v.verse || v.text || v.content || '').trim()
        }));
      }
      return out;
    }

    async function netlifyVersions() {
      if (RUNTIME_FLAGS.netlifyCorsBlocked) return [];
      const payload = await fetchJSON(CONFIG.API_SOURCES.primary + '/versions');
      const list = Array.isArray(payload) ? payload : (payload.versions || payload.data || []);
      return list.map(v => {
        const rawId = String(v.version || v.id || '').trim().toLowerCase();
        const allowed = VERSION_POLICY.netlifyAllowed[rawId];
        if (!allowed) return null;
        return {
          id: allowed.id,
          rawId: rawId,
          name: allowed.name,
          language: 'spa',
          availableIn: ['netlify']
        };
      }).filter(Boolean);
    }

    async function helloVersions() {
      const payload = await fetchJSON(CONFIG.API_SOURCES.secondary + '/available_translations.json');
      const list = Array.isArray(payload) ? payload : (payload.translations || payload.data || []);
      return list.map(v => ({
        id: normalizeVersionId(v.id || v.shortName || v.name),
        rawId: String(v.id || v.shortName || v.name || '').trim(),
        name: v.name || v.shortName || v.id || 'Version',
        language: String(v.language || v.lang || '').toLowerCase(),
        availableIn: ['helloao']
      })).filter(v => v.id && v.language === 'spa');
    }

    async function getVersions() {
      const [netlifyList, helloList] = await Promise.allSettled([netlifyVersions(), helloVersions()]);
      const merged = {};

      function upsert(list) {
        list.forEach(v => {
          if (!merged[v.id]) {
            merged[v.id] = {
              id: v.id,
              name: v.name,
              language: v.language,
              availableIn: [],
              sourceIds: { netlify: [], helloao: [] }
            };
          }
          v.availableIn.forEach(src => {
            if (merged[v.id].availableIn.indexOf(src) === -1) {
              merged[v.id].availableIn.push(src);
            }
            if (v.rawId && merged[v.id].sourceIds[src].indexOf(v.rawId) === -1) {
              merged[v.id].sourceIds[src].push(v.rawId);
            }
          });
        });
      }

      if (netlifyList.status === 'fulfilled') upsert(netlifyList.value);
      if (helloList.status === 'fulfilled') upsert(helloList.value);

      const output = Object.keys(merged).map(k => merged[k]).sort((a, b) => a.name.localeCompare(b.name, 'es'));
      if (output.length === 0) {
        return [{ id: CONFIG.DEFAULT_VERSION, name: 'Reina Valera 1960', language: 'spa', availableIn: ['helloao'], default: true }];
      }

      return output.map(v => ({ ...v, default: v.id === CONFIG.DEFAULT_VERSION }));
    }

    async function getChapterFromNetlify(versionId, bookValue, chapter) {
      if (RUNTIME_FLAGS.netlifyCorsBlocked) {
        throw new Error('Netlify API bloqueada por CORS en este origen');
      }
      const url = CONFIG.API_SOURCES.primary
        + '/api/read/' + encodeURIComponent(String(versionId).toLowerCase())
        + '/' + encodeURIComponent(String(bookValue).toLowerCase())
        + '/' + encodeURIComponent(String(chapter));
      const payload = await fetchJSON(url);
      return parseNetlifyChapter(payload, versionId, bookValue, chapter);
    }

    async function getChapterFromHello(versionId, bookId, chapter) {
      const url = CONFIG.API_SOURCES.secondary + '/' + encodeURIComponent(versionId) + '/' + encodeURIComponent(String(bookId).toUpperCase()) + '/' + encodeURIComponent(String(chapter)) + '.json';
      const payload = await fetchJSON(url);
      return parseHelloChapter(payload, versionId, bookId, chapter);
    }

    function getVersionCandidatesForSource(versionRecord, source) {
      const direct = versionRecord && versionRecord.sourceIds && versionRecord.sourceIds[source]
        ? versionRecord.sourceIds[source].slice()
        : [];

      const normalized = normalizeVersionId((versionRecord && versionRecord.id) || CONFIG.DEFAULT_VERSION);
      const map = {
        'RV1960': ['RV1960', 'RVR1960', 'RV60', 'RVR60', 'rv1960', 'rvr1960', 'RVA', 'rva'],
        'RV1995': ['RV1995', 'RVR1995', 'rv1995', 'rvr1995'],
        'NVI': ['NVI', 'nvi'],
        'DHH': ['DHH', 'dhh'],
        'PDT': ['PDT', 'pdt'],
        'RVR1909': ['RVR1909', 'RV1909', 'rvr1909']
      };

      const alias = map[normalized] || [normalized, normalized.toLowerCase()];
      const all = direct.concat(alias);
      return all.filter((v, i) => v && all.indexOf(v) === i);
    }

    function getBookCandidates(source, bookId, options) {
      const out = [String(bookId).toUpperCase()];
      const bookName = options && options.bookName ? String(options.bookName).trim() : '';
      if (source === 'netlify' && bookName) {
        out.push(bookName);
        out.push(bookName.toLowerCase());
      }
      return out.filter((v, i) => v && out.indexOf(v) === i);
    }

    async function getChapter(versionId, bookId, chapter, options) {
      const normalizedVersion = normalizeVersionId(versionId || CONFIG.DEFAULT_VERSION);
      const allVersions = await getVersions();
      const versionRecord = allVersions.find(v => v.id === normalizedVersion) || {
        id: normalizedVersion,
        availableIn: RUNTIME_FLAGS.netlifyCorsBlocked ? ['helloao'] : ['netlify', 'helloao'],
        sourceIds: { netlify: [], helloao: [] }
      };

      const order = orderSources(versionRecord);
      const errors = [];

      for (let i = 0; i < order.length; i += 1) {
        const source = order[i];
        const versionCandidates = getVersionCandidatesForSource(versionRecord, source);
        const bookCandidates = getBookCandidates(source, bookId, options);

        for (let v = 0; v < versionCandidates.length; v += 1) {
          const sourceVersion = versionCandidates[v];
          for (let b = 0; b < bookCandidates.length; b += 1) {
            const sourceBook = bookCandidates[b];
            const cached = getCachedChapter(source, sourceVersion, sourceBook, chapter);
            if (cached) return cached;

            try {
              const data = source === 'netlify'
                ? await getChapterFromNetlify(sourceVersion, sourceBook, chapter)
                : await getChapterFromHello(sourceVersion, sourceBook, chapter);
              setCachedChapter(source, sourceVersion, sourceBook, chapter, data);
              return data;
            } catch (e) {
              errors.push({ source: source, version: sourceVersion, book: sourceBook, message: e.message, status: e.status || null });
            }
          }
        }
      }

      const err = new Error('No se pudo cargar el capitulo solicitado desde ninguna API.');
      err.details = errors;
      throw err;
    }

    return {
      getVersions,
      getChapter,
      normalizeVersionId
    };
  })();

  // ==========================================
  // Sistema de temas
  // ==========================================
  function initTheme() {
    const savedTheme = localStorage.getItem('theme');
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

    state.theme = savedTheme || (prefersDark ? 'dark' : 'light');
    applyTheme();

    const toggleBtn = $('#theme-toggle');
    if (toggleBtn) {
      toggleBtn.addEventListener('click', toggleTheme);
    }
  }

  function applyTheme() {
    document.documentElement.setAttribute('data-theme', state.theme);

    const sunIcon = $('.icon-sun');
    const moonIcon = $('.icon-moon');

    if (state.theme === 'dark') {
      hide(sunIcon);
      show(moonIcon);
    } else {
      show(sunIcon);
      hide(moonIcon);
    }
  }

  function toggleTheme() {
    state.theme = state.theme === 'light' ? 'dark' : 'light';
    localStorage.setItem('theme', state.theme);
    applyTheme();
  }

  // ==========================================
  // Navegación y detección de página
  // ==========================================
  function detectCurrentPage() {
    const path = window.location.pathname;

    if (path === '/' || path === '') {
      return 'home';
    }

    const pageMap = {
      '/p/leer-hoy.html': 'leer-hoy',
      '/p/planes.html': 'planes',
      '/p/plan-completo.html': 'plan-completo',
      '/p/biblia.html': 'biblia',
      '/p/buscar.html': 'buscar',
      '/p/mi-espacio.html': 'mi-espacio',
      '/p/acerca.html': 'acerca',
      '/p/preguntas-frecuentes.html': 'faq',
      '/p/instalar.html': 'instalar'
    };

    return pageMap[path] || 'home';
  }

  function updateActiveNav() {
    const page = state.currentPage;

    // Desktop nav
    $$('.nav-link').forEach(link => {
      const linkPage = link.getAttribute('data-page');
      if (linkPage === page) {
        link.classList.add('active');
      } else {
        link.classList.remove('active');
      }
    });

    // Mobile nav
    $$('.nav-mobile-item').forEach(item => {
      const itemPage = item.getAttribute('data-page');
      if (itemPage === page) {
        item.classList.add('active');
      } else {
        item.classList.remove('active');
      }
    });
  }

  // ==========================================
  // Gestión de datos del usuario
  // ==========================================
  function getUserData() {
    try {
      const data = localStorage.getItem(CONFIG.STORAGE_KEY);
      return data ? JSON.parse(data) : null;
    } catch (e) {
      console.error('Error reading user data:', e);
      return null;
    }
  }

  function saveUserData(data) {
    try {
      localStorage.setItem(CONFIG.STORAGE_KEY, JSON.stringify(data));
    } catch (e) {
      console.error('Error saving user data:', e);
    }
  }

  function migrateLegacyStorage() {
    try {
      if (localStorage.getItem(CONFIG.STORAGE_KEY)) return;

      const legacyData = {
        config: {
          preferredVersion: localStorage.getItem(CONFIG.STORAGE_LEGACY_PREFIX + 'preferredVersion') || CONFIG.DEFAULT_VERSION,
          sourcePreference: CONFIG.SOURCE_PREFERENCE,
          darkMode: state.theme === 'dark',
          fontSize: 'medium',
          activePlanId: null,
          leapYearMode: 'gracia'
        },
        plans: [],
        favorites: [],
        notes: [],
        history: {
          readings: [],
          searches: [],
          chapters: []
        }
      };

      const legacyActivePlan = localStorage.getItem(CONFIG.STORAGE_LEGACY_PREFIX + 'activePlan');
      const legacyProgress = localStorage.getItem(CONFIG.STORAGE_LEGACY_PREFIX + 'progress');
      const legacyFavorites = localStorage.getItem(CONFIG.STORAGE_LEGACY_PREFIX + 'favorites');
      const legacyNotes = localStorage.getItem(CONFIG.STORAGE_LEGACY_PREFIX + 'notes');

      if (legacyActivePlan) {
        legacyData.config.activePlanId = JSON.parse(legacyActivePlan);
      }
      if (legacyProgress) {
        legacyData.history.readings = JSON.parse(legacyProgress).completed || [];
      }
      if (legacyFavorites) {
        legacyData.favorites = JSON.parse(legacyFavorites);
      }
      if (legacyNotes) {
        legacyData.notes = JSON.parse(legacyNotes);
      }

      const hasLegacyContent = legacyActivePlan || legacyProgress || legacyFavorites || legacyNotes;
      if (!hasLegacyContent) return;

      const migrated = {
        version: '1.0',
        lastSync: new Date().toISOString().split('T')[0],
        ...legacyData
      };

      saveUserData(migrated);
    } catch (e) {
      console.warn('Legacy storage migration skipped:', e);
    }
  }

  function initUserData() {
    migrateLegacyStorage();
    const data = getUserData();

    if (!data) {
      // Crear estructura inicial
      const initialData = {
        version: '1.0',
        lastSync: new Date().toISOString().split('T')[0],
        config: {
          preferredVersion: CONFIG.DEFAULT_VERSION,
          sourcePreference: CONFIG.SOURCE_PREFERENCE,
          darkMode: state.theme === 'dark',
          fontSize: 'medium',
          activePlanId: null,
          leapYearMode: 'gracia'
        },
        plans: [],
        favorites: [],
        notes: [],
        history: {
          readings: [],
          searches: [],
          chapters: []
        }
      };

      saveUserData(initialData);
      state.user = initialData;
    } else {
      if (!data.config) data.config = {};
      data.config.preferredVersion = normalizeVersionId(data.config.preferredVersion || CONFIG.DEFAULT_VERSION);
      if (!data.config.sourcePreference) data.config.sourcePreference = CONFIG.SOURCE_PREFERENCE;
      state.user = data;
      state.version = data.config.preferredVersion || CONFIG.DEFAULT_VERSION;
    }
  }

  // ==========================================
  // Actualización de UI
  // ==========================================
  function updateHomeProgress() {
    const userData = state.user;
    const progressSection = $('#progress-section');

    if (!userData || !userData.config.activePlanId) {
      hide(progressSection);
      return;
    }

    const activePlan = userData.plans.find(p => p.planId === userData.config.activePlanId);

    if (!activePlan) {
      hide(progressSection);
      return;
    }

    show(progressSection);

    const planName = $('#plan-name');
    const progressPercent = $('#progress-percent');
    const progressFill = $('#progress-fill');
    const progressStatus = $('#progress-status');

    if (planName) planName.textContent = 'Biblia en un año';

    const completed = activePlan.completedDays.length;
    const percent = Math.round((completed / 365) * 100);

    if (progressPercent) progressPercent.textContent = percent + '%';
    if (progressFill) progressFill.style.width = percent + '%';
    if (progressStatus) progressStatus.textContent = 'Día ' + activePlan.lastOpenedDay + ' de 365';
  }

  async function loadHomeDailyVerse() {
    const verseTextEl = $('#verse-text');
    const verseRefEl = $('#verse-reference');
    if (!verseTextEl || !verseRefEl) return;

    const preferredVersion = normalizeVersionId(
      (state.user && state.user.config && state.user.config.preferredVersion) || CONFIG.DEFAULT_VERSION
    );

    try {
      const chapterData = await BibleService.getChapter(preferredVersion, 'PSA', 119, { bookName: 'Salmos' });
      const verses = Array.isArray(chapterData.verses) ? chapterData.verses : [];
      const verse = verses.find(v => Number(v.number) === 105);

      if (!verse || !verse.text) {
        throw new Error('Verse not found in chapter response');
      }

      verseTextEl.textContent = verse.text;
      verseRefEl.textContent = 'Salmos 119:105 (' + preferredVersion + ')';
    } catch (error) {
      console.warn('Daily verse fallback to static content:', error);
    }
  }

  function showCurrentPageContainer() {
    const home = $('#page-home');
    const dynamic = $('#page-dynamic');

    if (state.currentPage === 'home') {
      show(home);
      hide(dynamic);
    } else {
      hide(home);
      show(dynamic);
    }
  }

  function normalizeBookName(input) {
    return String(input || '')
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .toLowerCase()
      .replace(/\./g, '')
      .replace(/\s+/g, ' ')
      .trim();
  }

  function getBookIdFromSpanishName(bookName) {
    const map = {
      'genesis': 'GEN', 'exodo': 'EXO', 'levitico': 'LEV', 'numeros': 'NUM', 'deuteronomio': 'DEU',
      'josue': 'JOS', 'jueces': 'JDG', 'rut': 'RUT', '1 samuel': '1SA', '2 samuel': '2SA',
      '1 reyes': '1KI', '2 reyes': '2KI', '1 cronicas': '1CH', '2 cronicas': '2CH', 'esdras': 'EZR',
      'nehemias': 'NEH', 'ester': 'EST', 'job': 'JOB', 'salmos': 'PSA', 'proverbios': 'PRO',
      'eclesiastes': 'ECC', 'cantares': 'SNG', 'isaias': 'ISA', 'jeremias': 'JER', 'lamentaciones': 'LAM',
      'ezequiel': 'EZK', 'daniel': 'DAN', 'oseas': 'HOS', 'joel': 'JOL', 'amos': 'AMO',
      'abdias': 'OBA', 'jonas': 'JON', 'miqueas': 'MIC', 'nahum': 'NAM', 'habacuc': 'HAB',
      'sofonias': 'ZEP', 'hageo': 'HAG', 'zacarias': 'ZEC', 'malaquias': 'MAL', 'mateo': 'MAT',
      'marcos': 'MRK', 'lucas': 'LUK', 'juan': 'JHN', 'hechos': 'ACT', 'romanos': 'ROM',
      '1 corintios': '1CO', '2 corintios': '2CO', 'galatas': 'GAL', 'efesios': 'EPH', 'filipenses': 'PHP',
      'colosenses': 'COL', '1 tesalonicenses': '1TH', '2 tesalonicenses': '2TH', '1 timoteo': '1TI', '2 timoteo': '2TI',
      'tito': 'TIT', 'filemon': 'PHM', 'hebreos': 'HEB', 'santiago': 'JAS', '1 pedro': '1PE',
      '2 pedro': '2PE', '1 juan': '1JN', '2 juan': '2JN', '3 juan': '3JN', 'judas': 'JUD', 'apocalipsis': 'REV'
    };
    return map[normalizeBookName(bookName)] || null;
  }

  function parseReadingReference(reference) {
    const cleaned = String(reference || '').trim();
    const match = cleaned.match(/^(.*)\s+(\d+)$/);
    if (!match) return null;
    const bookName = match[1].trim();
    const chapter = Number(match[2]);
    const bookId = getBookIdFromSpanishName(bookName);
    if (!bookId || !chapter) return null;
    return { reference: cleaned, bookName: bookName, bookId: bookId, chapter: chapter };
  }

  function getDaysSince(startDateIso) {
    const start = new Date(startDateIso + 'T00:00:00');
    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    return Math.floor((today - start) / 86400000) + 1;
  }

  function ensureActiveAnnualPlan() {
    if (!state.user) return null;
    if (!Array.isArray(state.user.plans)) state.user.plans = [];

    let activeId = state.user.config.activePlanId;
    let plan = state.user.plans.find(p => p.planId === activeId);

    if (!plan) {
      plan = {
        planId: 'Plan_Anual',
        name: 'Plan Anual',
        startDate: new Date().toISOString().split('T')[0],
        completedDays: [],
        lastOpenedDay: 1
      };
      state.user.plans.push(plan);
      state.user.config.activePlanId = plan.planId;
      saveUserData(state.user);
    }

    return plan;
  }

  async function loadAnnualPlanDays() {
    const url = CONFIG.CDN_BASE + 'json/Plan_Anual.json';
    const res = await fetch(url);
    if (!res.ok) throw new Error('No se pudo cargar Plan_Anual.json');
    return res.json();
  }

  function renderChapterVerses(verses) {
    if (!Array.isArray(verses) || verses.length === 0) {
      return '<p class="text-muted">No se encontraron versículos para este capítulo.</p>';
    }

    return verses.map(v => (
      '<p><strong>' + v.number + '</strong> ' + v.text + '</p>'
    )).join('');
  }

  async function renderLeerHoyPage() {
    const dynamic = $('#page-dynamic');
    if (!dynamic) return;

    dynamic.innerHTML = '<div class="loading-container"><div class="loading-spinner"></div><p class="text-muted">Cargando lectura de hoy...</p></div>';

    try {
      const planState = ensureActiveAnnualPlan();
      const allDays = await loadAnnualPlanDays();
      const todayDay = Math.min(Math.max(getDaysSince(planState.startDate), 1), Array.isArray(allDays) ? allDays.length : 365);
      planState.lastOpenedDay = todayDay;
      saveUserData(state.user);

      const dayData = allDays.find(d => Number(d.dia) === todayDay) || allDays[0];
      const readings = Array.isArray(dayData.porciones) ? dayData.porciones : [];
      const parsedReadings = readings.map(parseReadingReference).filter(Boolean);
      if (parsedReadings.length === 0) {
        throw new Error('No se pudo interpretar la lectura del día.');
      }

      const versions = await BibleService.getVersions();
      const preferredVersion = normalizeVersionId(state.user.config.preferredVersion || CONFIG.DEFAULT_VERSION);
      const versionExists = versions.some(v => v.id === preferredVersion);
      const selectedVersion = versionExists ? preferredVersion : (versions[0] ? versions[0].id : CONFIG.DEFAULT_VERSION);
      state.user.config.preferredVersion = selectedVersion;
      saveUserData(state.user);

      let currentReadingIndex = 0;
      const firstReading = parsedReadings[currentReadingIndex];
      const chapterData = await BibleService.getChapter(selectedVersion, firstReading.bookId, firstReading.chapter, { bookName: firstReading.bookName });

      dynamic.innerHTML = [
        '<div class="page-container">',
          '<section class="card" style="margin-bottom:16px;">',
            '<h2 style="margin-bottom:8px;">Leer hoy</h2>',
            '<p class="text-muted">Día ' + todayDay + ' de 365</p>',
            '<p style="margin-top:8px;"><strong>Lecturas:</strong> ' + readings.join(' · ') + '</p>',
          '</section>',
          '<section class="card" style="margin-bottom:16px;">',
            '<label class="text-muted" for="version-select">Versión bíblica</label>',
            '<select id="version-select" style="width:100%;margin-top:8px;padding:10px;border-radius:8px;border:1px solid var(--border-light);background:var(--bg-secondary);color:var(--text-primary);">',
              versions.map(function(v) {
                const selected = v.id === selectedVersion ? ' selected' : '';
                return '<option value="' + v.id + '"' + selected + '>' + v.name + ' (' + v.id + ')</option>';
              }).join(''),
            '</select>',
          '</section>',
          '<section class="card" id="chapter-reading">',
            '<div style="display:flex;justify-content:space-between;gap:8px;align-items:center;margin-bottom:12px;">',
              '<button class="btn" id="reading-prev-btn" type="button">Anterior</button>',
              '<p class="text-muted" id="reading-index-label">Lectura 1 de ' + parsedReadings.length + '</p>',
              '<button class="btn" id="reading-next-btn" type="button">Siguiente</button>',
            '</div>',
            '<h3 style="margin-bottom:12px;" id="chapter-title">' + firstReading.reference + ' (' + selectedVersion + ')</h3>',
            '<div id="chapter-verses">' + renderChapterVerses(chapterData.verses) + '</div>',
            '<button class="btn btn-primary" id="mark-read-btn" style="margin-top:16px;">Marcar como leído</button>',
            '<p class="text-muted mt-md" id="mark-read-msg"></p>',
          '</section>',
        '</div>'
      ].join('');

      async function renderCurrentReading() {
        const reading = parsedReadings[currentReadingIndex];
        const currentVersion = normalizeVersionId((state.user && state.user.config && state.user.config.preferredVersion) || selectedVersion);
        const title = $('#chapter-title');
        const versesBox = $('#chapter-verses');
        const label = $('#reading-index-label');
        const prevBtn = $('#reading-prev-btn');
        const nextBtn = $('#reading-next-btn');

        if (label) label.textContent = 'Lectura ' + (currentReadingIndex + 1) + ' de ' + parsedReadings.length;
        if (title) title.textContent = reading.reference + ' (' + currentVersion + ')';
        if (prevBtn) prevBtn.disabled = currentReadingIndex === 0;
        if (nextBtn) nextBtn.disabled = currentReadingIndex === parsedReadings.length - 1;

        if (versesBox) versesBox.innerHTML = '<p class="text-muted">Cargando capítulo...</p>';
        try {
          const currentChapter = await BibleService.getChapter(currentVersion, reading.bookId, reading.chapter, { bookName: reading.bookName });
          if (versesBox) versesBox.innerHTML = renderChapterVerses(currentChapter.verses);
        } catch (_) {
          if (versesBox) versesBox.innerHTML = '<p class="text-muted">No se pudo cargar la lectura. Intenta otra versión.</p>';
        }
      }

      const versionSelect = $('#version-select');
      if (versionSelect) {
        versionSelect.addEventListener('change', async function() {
          const nextVersion = normalizeVersionId(versionSelect.value);
          state.user.config.preferredVersion = nextVersion;
          saveUserData(state.user);
          await renderCurrentReading();
        });
      }

      const prevBtn = $('#reading-prev-btn');
      if (prevBtn) {
        prevBtn.addEventListener('click', async function() {
          if (currentReadingIndex > 0) {
            currentReadingIndex -= 1;
            await renderCurrentReading();
          }
        });
      }

      const nextBtn = $('#reading-next-btn');
      if (nextBtn) {
        nextBtn.addEventListener('click', async function() {
          if (currentReadingIndex < parsedReadings.length - 1) {
            currentReadingIndex += 1;
            await renderCurrentReading();
          }
        });
      }

      await renderCurrentReading();

      const markBtn = $('#mark-read-btn');
      if (markBtn) {
        markBtn.addEventListener('click', function() {
          if (planState.completedDays.indexOf(todayDay) === -1) {
            planState.completedDays.push(todayDay);
            planState.completedDays.sort(function(a, b) { return a - b; });
            saveUserData(state.user);
          }
          const msg = $('#mark-read-msg');
          if (msg) msg.textContent = '¡Bien! Un día más en Su Palabra.';
        });
      }
    } catch (error) {
      dynamic.innerHTML = [
        '<div class="page-container">',
          '<section class="card">',
            '<h2 style="margin-bottom:8px;">Leer hoy</h2>',
            '<p class="text-muted">No pudimos cargar la lectura. Verifica tu conexión e intenta de nuevo.</p>',
            '<p class="text-muted mt-md">Detalle técnico: ' + (error && error.message ? error.message : 'Error desconocido') + '</p>',
          '</section>',
        '</div>'
      ].join('');
    }
  }

  function renderPlanesPage() {
    const dynamic = $('#page-dynamic');
    if (!dynamic) return;

    const userData = state.user;
    const activePlanId = userData && userData.config ? userData.config.activePlanId : null;

    dynamic.innerHTML = [
      '<div class="page-container">',
        '<section style="margin-bottom:20px;">',
          '<h1 style="font-family:var(--font-serif);font-size:1.8rem;font-weight:600;margin-bottom:6px;">Planes de lectura</h1>',
          '<p class="text-muted">Elige un plan y comienza tu lectura estructurada de la Biblia.</p>',
        '</section>',
        '<div id="plans-list"><div class="loading-container"><div class="loading-spinner"></div><p class="text-muted">Cargando planes...</p></div></div>',
      '</div>'
    ].join('');

    fetch(CONFIG.CDN_BASE + 'json/plans.json')
      .then(function(r) { return r.json(); })
      .then(function(plans) {
        const listEl = $('#plans-list');
        if (!listEl) return;

        if (!Array.isArray(plans) || plans.length === 0) {
          listEl.innerHTML = '<p class="text-muted">No se encontraron planes disponibles.</p>';
          return;
        }

        listEl.innerHTML = plans.map(function(plan) {
          const isActive = plan.id === activePlanId;
          const label = isActive ? '<span class="chip" style="background:var(--accent-primary);color:#fff;font-size:0.75rem;">Activo</span>' : '';

          return [
            '<div class="card" style="margin-bottom:14px;padding:18px;">',
              '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;margin-bottom:10px;">',
                '<div>',
                  '<h2 style="font-size:1.05rem;font-weight:700;margin:0 0 4px;">' + plan.name + '</h2>',
                  '<span class="text-muted" style="font-size:0.85rem;">' + plan.days + ' días</span>',
                '</div>',
                label,
              '</div>',
              '<div style="display:flex;gap:10px;margin-top:12px;">',
                isActive
                  ? '<a class="btn btn-primary" href="' + (window.location.origin + '/p/leer-hoy.html') + '" style="font-size:0.88rem;min-height:40px;padding:0 14px;">Continuar</a>'
                  : '<button class="btn btn-primary" data-plan-id="' + plan.id + '" data-plan-name="' + plan.name + '" onclick="window.MiBiblia365StartPlan && window.MiBiblia365StartPlan(this)" style="font-size:0.88rem;min-height:40px;padding:0 14px;">Iniciar plan</button>',
              '</div>',
            '</div>'
          ].join('');
        }).join('');
      })
      .catch(function() {
        const listEl = $('#plans-list');
        if (listEl) listEl.innerHTML = '<p class="text-muted">No se pudieron cargar los planes. Verifica tu conexión.</p>';
      });

    window.MiBiblia365StartPlan = function(btn) {
      const planId = btn.getAttribute('data-plan-id');
      const planName = btn.getAttribute('data-plan-name');
      if (!state.user) return;
      if (!Array.isArray(state.user.plans)) state.user.plans = [];
      const existing = state.user.plans.find(function(p) { return p.planId === planId; });
      if (!existing) {
        state.user.plans.push({
          planId: planId,
          name: planName,
          startDate: new Date().toISOString().split('T')[0],
          completedDays: [],
          lastOpenedDay: 1
        });
      }
      state.user.config.activePlanId = planId;
      saveUserData(state.user);
      window.location.href = '/p/leer-hoy.html';
    };
  }

