  function renderPlaceholderPage(title, description) {
    const dynamic = $('#page-dynamic');
    if (!dynamic) return;

    dynamic.innerHTML = [
      '<div class="page-container">',
        '<section class="card">',
          '<h1 style="font-family:var(--font-serif);font-size:1.6rem;font-weight:600;margin-bottom:8px;">' + title + '</h1>',
          '<p class="text-muted">' + description + '</p>',
        '</section>',
      '</div>'
    ].join('');
  }

  async function renderCurrentPage() {
    showCurrentPageContainer();

    switch (state.currentPage) {
      case 'leer-hoy':
        await renderLeerHoyPage();
        break;
      case 'planes':
        renderPlanesPage();
        break;
      case 'acerca':
        renderAcercaPage();
        break;
      case 'faq':
        renderFAQPage();
        break;
      case 'instalar':
        renderInstalarPage();
        break;
      case 'biblia':
        renderPlaceholderPage('Explorar Biblia', 'Aquí podrás navegar libremente cualquier libro y capítulo de la Biblia. Esta función estará disponible en la siguiente fase.');
        break;
      case 'buscar':
        renderPlaceholderPage('Buscar en la Biblia', 'El buscador bíblico estará disponible próximamente. Podrás buscar palabras o frases en toda la Biblia.');
        break;
      case 'mi-espacio':
        renderPlaceholderPage('Mi espacio', 'Aquí encontrarás tu progreso, favoritos, notas y configuración personal. Esta sección estará completa próximamente.');
        break;
      case 'plan-completo':
        renderPlaceholderPage('Plan completo', 'El calendario completo de tu plan de lectura estará disponible próximamente.');
        break;
      default:
        break;
    }
  }

  // ==========================================
  // Inicialización
  // ==========================================
  function init() {
    initTheme();
    initUserData();
    window.MiBiblia365Services = window.MiBiblia365Services || {};
    window.MiBiblia365Services.bible = BibleService;

    const footerYear = $('#footer-year');
    if (footerYear) footerYear.textContent = new Date().getFullYear();

    state.currentPage = detectCurrentPage();
    updateActiveNav();
    renderCurrentPage();

    // Actualizar UI según página actual
    if (state.currentPage === 'home') {
      updateHomeProgress();
      loadHomeDailyVerse();
    }

    // Escuchar cambios de tema del sistema
    window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', (e) => {
      if (!localStorage.getItem('theme')) {
        state.theme = e.matches ? 'dark' : 'light';
        applyTheme();
      }
    });

    console.log('Mi Biblia 365 initialized');
  }

  // Ejecutar cuando el DOM esté listo
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

})();
